    'hero.badge': 'Principal Software Engineer | AI Specialist | Cloud Infrastructure & AWS Expert',
    'hero.h1Line1': 'Build with rigor.',
    'hero.h1Line2': 'Ship what lasts.',
    'hero.sub': "I'm João, a developer for the past 6 years. I work across the TypeScript ecosystem, Node, Angular, React and React Native, building enterprise-grade scalable applications. I specialize in AWS infrastructure and in developing with AI through Spec Driven Development.",
    'hero.yearsBuilding': 'Years building',
